import * as Immutable from 'immutable'
import { List } from 'immutable'

import BackendPermissions from '@/models/BackendPermissions'
import { SignatureFeatureAvailability } from '@/enums/SignatureFeatureAvailability'

import type { FontSubstitution } from '@/models/FontSubstitution'
import type { IProcessorEngine } from '@/enums/ProcessorEngine'
import type { DocumentResponse as CoreDocumentResponse, PageInfoResponse } from '@pspdfkit/core'
import type { SignaturesInfo } from '@/models/digital-signatures/SignaturesInfo'
import type { ISignatureFeatureAvailability } from '@/enums/SignatureFeatureAvailability'
import type Font from '@/models/Font'
import type { ILicenseFeature } from '@/enums/LicenseFeature'
import type { TrustedCAsCallback } from '@/models/digital-signatures/TrustedCAsCallback'
import type { IProductId } from '@/enums/ProductId'

interface IStandaloneBackendState {
  baseUrl: string | null
  baseCoreUrl: string | null
  baseProcessorEngineUrl: string | null
  licenseKey: string | undefined | null
  document: string | ArrayBuffer | null
  backendPermissions: BackendPermissions
  documentResponse: CoreDocumentResponse | null
  disableWebAssemblyStreaming: boolean
  enableAutomaticLinkExtraction: boolean
  overrideMemoryLimit: null | number
  features: List<string>
  signatureFeatureAvailability: ISignatureFeatureAvailability
  documentHandle: string | null
  signaturesInfoPromise: Promise<SignaturesInfo> | null | undefined
  customFonts: null | Array<Font>
  forceLegacySignaturesFeature: boolean
  trustedCAsCallback: TrustedCAsCallback | null
  forceAnnotationsRender: boolean
  appName: string | null
  lazyLoadedPages: Array<PageInfoResponse> | null
  productId: IProductId | null
  processorEngine: IProcessorEngine | null
  dynamicFonts: string | null
  fontSubstitutions: FontSubstitution[] | null
  inlineWorkers: boolean
}

export default class StandaloneBackendState extends Immutable.Record<IStandaloneBackendState>({
  baseUrl: null,
  baseCoreUrl: null,
  baseProcessorEngineUrl: null,
  licenseKey: null,
  document: null,
  backendPermissions: new BackendPermissions(),
  documentResponse: null,
  disableWebAssemblyStreaming: false,
  enableAutomaticLinkExtraction: false,
  overrideMemoryLimit: null,
  features: List(),
  signatureFeatureAvailability: SignatureFeatureAvailability.NONE,
  documentHandle: null,
  trustedCAsCallback: null,
  signaturesInfoPromise: null,
  customFonts: null,
  fontSubstitutions: null,
  forceLegacySignaturesFeature: false,
  forceAnnotationsRender: false,
  appName: null,
  lazyLoadedPages: null,
  productId: null,
  processorEngine: null,
  dynamicFonts: null,
  inlineWorkers: true,
}) {
  /**
   * URL to the PSPDFKit client code, e.g: `https://pspdfkit.example.com/`
   */
  override baseUrl: string

  /**
   * URL to the PSPDFKit WASM artifact and JavaScript wrapper, e.g: `https://pspdfkit.example.com/`
   */
  override baseCoreUrl: string

  /**
   * URL to the GdPicture WASM assets, e.g: `https://pspdfkit.example.com/`
   */
  override baseProcessorEngineUrl: string

  /**
   * License Key for PSPDFKit
   */
  override licenseKey: string | undefined | null

  /**
   * URL to the document
   */
  override document: string | ArrayBuffer

  /**
   * Defines if the user is allowed to edit annotations or download the document
   */
  override backendPermissions: BackendPermissions

  /**
   * The document response is returned when initializing core, we cache the
   * result here so we can implement the `documentInfo` call properly.
   */
  override documentResponse: CoreDocumentResponse

  /**
   * Disable WebAssembly streaming instantiation when `true`
   */
  override disableWebAssemblyStreaming: boolean

  /**
   * No artificial link annotations will be created when `true`
   */
  override enableAutomaticLinkExtraction: boolean

  /**
   * Overrides the default WASM/ASM.js memory limits. Unit is megabytes.
   */
  override overrideMemoryLimit: null | number

  /**
   * PSPDFKit license features, used to detect which features can be used.
   */
  override features: List<ILicenseFeature>

  /**
   * Determines which variant of signatures UI is shown
   */
  override signatureFeatureAvailability: ISignatureFeatureAvailability

  /**
   * Opaque string corresponding to the current document. This field is updated when operations
   * are applied on the document.
   */
  override documentHandle: string

  /**
   * Persists the Promise object created in the first call to getSignaturesInfo, which resolves
   * with the document's signature validation info.
   */
  override signaturesInfoPromise: Promise<SignaturesInfo> | null | undefined

  /**
   * Custom fonts to use
   */
  override customFonts: null | Array<Font>

  /**
   * Marks if even though Electronic Signatures licensed for the current user,
   * the legacy signature mode should be used instead.
   */
  override forceLegacySignaturesFeature: boolean

  /**
   * Force rendering annotations when rendering tiles even when no annotations are
   * passed as `contentState` to `renderTile()`. Used in document comparison mode
   * to render the annotations in the background.
   */
  override forceAnnotationsRender: boolean

  /**
   * Use as Maui, Flutter for Web or Electron application name to match against the license bundle ID when using
   * Maui, Flutter for Web or Electron with context isolation.
   */
  override appName: string | null

  /**
   * Contains information from all the pages, once it has been retrieved.
   */
  override lazyLoadedPages: Array<PageInfoResponse> | null

  /**
   * Indicates the ID of the product, if SharePoint or Salesforce.
   */
  override productId: IProductId | null

  /**
   * Indicates the build preference for the current environment.
   * This is used to determine which build to use when loading PSPDFKit.
   * The default value is `fasterProcessing`.
   * other possible value are `smallerSize`.
   */
  override processorEngine: IProcessorEngine | null
  /**
   * URL to the dynamic fonts file.
   */
  override dynamicFonts: string | null
  /**
   * Flag that defines whether the worker will be loaded from a file, or inline using `blob:`
   */
  override inlineWorkers: boolean
}
