import { CorePDF } from '@pspdfkit/core-pdf'
import { List } from 'immutable'

import { isModifiableAnnotation } from '@/utils/annotation'
import {
  serializeAnnotation,
  serializeFormField,
  serializeFormFieldValue,
} from '../serializers/utils'
import { bufferToImageHandle } from '@/utils/dom'
import { contentTreeIteratorParser, jsonToTextLines } from '@/utils/contentBlocks'

import type { Rect, Size, TextLine } from '@/PSPDFKit'
import type { ContentResponse, RenderTileContentState } from '@/typings/backend'
import type { IFunction } from '@/typings/utils'
import type ImageHandle from '../handles/ImageHandle'
import type { ContentBlock } from '@/models'

/**
 * A bridge to the CorePDF library.
 *
 * Easily access the context with the `ctx` property.
 *
 * Not super happy that we need this, but it makes mocking/testing massively easier..
 */
export class CorePDFBridge {
  ctx: CorePDF.Context

  constructor(ctx: CorePDF.Context) {
    this.ctx = ctx
  }

  renderTile(
    pageIndex: number,
    pageSize: Size,
    tileRect: Rect,
    renderForPrinting: boolean,
    renderText: boolean,
    contentState?: RenderTileContentState,
  ): {
    promise: Promise<ImageHandle<HTMLImageElement | HTMLCanvasElement>>
    cancel: IFunction
  } {
    let documentState: CorePDF.Renderer.DocumentRenderState | undefined = undefined

    if (contentState) {
      documentState = {
        annotations: contentState.annotations
          .filter(isModifiableAnnotation)
          .map(serializeAnnotation)
          .toJS()
          .map(content => ({
            content,
          })),
        formFieldValues: contentState.formFieldValues.map(serializeFormFieldValue).toJS(),
        formFields: contentState.formFields.map(serializeFormField).toJS(),
        signatures: contentState.signatures || [],
        attachments: contentState.attachments,
      }
    }

    const result = CorePDF.Renderer.renderTile(
      this.ctx,
      pageIndex,
      pageSize,
      tileRect,
      {
        renderForPrinting,
        renderText: renderText,
        priority:
          pageSize.width === tileRect.width && pageSize.height === tileRect.height
            ? CorePDF.Priority.High
            : CorePDF.Priority.Normal,
      },
      documentState,
    ).then(result => {
      return bufferToImageHandle({
        buffer: result.buffer,
        width: tileRect.width,
        height: tileRect.height,
        format: result.format,
      }).then(imageHandle => {
        if (imageHandle === null) throw new Error('Image handle is null')

        return imageHandle
      })
    })

    return {
      promise: result.promise,
      cancel: result.cancel,
    }
  }

  getTextLines(pageIndex: number): {
    promise: Promise<List<TextLine>>
    cancel: IFunction
  } {
    return CorePDF.Text.getTextForPage(this.ctx, pageIndex).then(result => {
      return jsonToTextLines(
        {
          textLines: result,
        },
        pageIndex,
      )
    })
  }

  getContentTree(pageIndex: number): {
    promise: Promise<ContentResponse>
    cancel: IFunction
  } {
    return CorePDF.Text.getContentTreeForPage(this.ctx, pageIndex).then(json => {
      let contentBlocks: Array<ContentBlock> = []
      let textLinesIndex = 0
      let contentElementsIndex = 0

      contentBlocks = json.reduce((acc: Array<ContentBlock>, { nodes }) => {
        const newContentBlocks = contentTreeIteratorParser(
          nodes,
          pageIndex,
          acc.length,
          textLinesIndex,
          contentElementsIndex,
        )

        textLinesIndex += newContentBlocks.reduce((acc, { textLines }) => acc + textLines.size, 0)
        contentElementsIndex += newContentBlocks.reduce(
          (acc, { contentElements }) => acc + contentElements.size,
          0,
        )

        return acc.concat(newContentBlocks)
      }, [])

      return List(contentBlocks)
    })
  }
}
