import { List, Map, Record, Set } from 'immutable'
import { PSPDFKitError, filterFalsyInstantJSONEntries, info, invariant } from '@pspdfkit/shared'
import { batch } from 'react-redux'

import {
  deserializeAnnotation,
  deserializeComment,
  deserializeFormField,
  deserializeFormFieldValue,
  serializeAnnotation,
  serializeComment,
  serializeFormField,
  serializeFormFieldValue,
} from '@/lib/serializers/utils'
import {
  fromJSON as deserializeBookmark,
  toJSON as serializeBookmark,
} from '@/lib/serializers/BookmarkSerializer'
import { generateAnnotationId } from '@/utils/annotation'
import { binaryImageToBlob } from '@/utils/images'
import { generateBookmarkId } from '@/utils/bookmark'
import { CREATE_REASON_LOAD } from '@/lib/Provider'

import type {
  Annotation,
  Attachment,
  Comment,
  FormField,
  FormFieldValue,
  WidgetAnnotation,
} from '@/models'
import type { ReadStateProvider, ReadStateProviderCallbacks } from '@/lib/ReadStateProvider'
import type { AnnotationProvider, AnnotationProviderCallbacks } from '@/lib/AnnotationProvider'
import type { BookmarkProvider, BookmarkProviderCallbacks } from '@/lib/BookmarkProvider'
import type { FormFieldProvider, FormFieldProviderCallbacks } from '@/lib/FormFieldProvider'
import type { FormFieldValueCallbacks, FormFieldValueProvider } from '@/lib/FormFieldValueProvider'
import type Bookmark from '@/models/Bookmark'
import type { ID as BookmarkID } from '@/models/Bookmark'
import type { ID } from '@/models/annotations/Annotation'
import type { CommentProvider, CommentProviderCallbacks } from '@/lib/CommentProvider'
import type { InstantJSON, SerializedJSON } from '@pspdfkit/shared'
import type { IObject } from '@/typings/utils'
import type { CommentJSON } from '@/typings/json/comment'
import type { FormFieldJSON } from '@/typings/json/formField'
import type { IClient } from '@/typings/models'
import type { AnnotationsBackendJSONUnion, AnnotationsUnion } from '@/typings/serializers'
import type { TabOrderIdsEntry } from '@pspdfkit/core'

class StandaloneProviderState extends Record({
  /**
   * Used to remember which page annotations have already been loaded.
   *
   * @member {Immutable.Map.<number, Promise.<void>>} alreadyLoadedPages
   */
  alreadyLoadedPages: Map() as Map<number, Promise<void>>,
  isLoaded: false,
  isDestroyed: false,
}) {}

const instantJSONStub: SerializedJSON = {
  skippedPdfObjectIds: [],
  skippedPdfBookmarkIds: [],
  annotations: [],
  bookmarks: [],
  formFieldValues: [],
  formFields: [],
  attachments: {},
}

export class StandaloneProvider
  implements
    ReadStateProvider,
    AnnotationProvider,
    BookmarkProvider,
    FormFieldProvider,
    FormFieldValueProvider,
    CommentProvider
{
  _core: IClient
  // Imported instantJSON is persisted here from the constructor,
  // and used on load() and in the form fields load callback.
  _json: SerializedJSON | null
  _readStateCallbacks: ReadStateProviderCallbacks | null | undefined
  _annotationCallbacks: AnnotationProviderCallbacks | null | undefined
  _bookmarkCallbacks: BookmarkProviderCallbacks | null | undefined
  _formFieldCallbacks: FormFieldProviderCallbacks | null | undefined
  _formFieldValueCallbacks: FormFieldValueCallbacks | null | undefined
  _commentCallbacks: CommentProviderCallbacks | null | undefined
  _state: StandaloneProviderState = new StandaloneProviderState()
  _formFieldsLoadedPromise: Promise<void> | null | undefined = null
  _objectCreationPromises: Map<ID, Promise<number | null | undefined>> = Map()
  _loadBookmarksPromise: Promise<void> | null | undefined = null
  _commentsLoadedPromise: Promise<void> | null | undefined = null
  _setReadStateCallbacksPromiseResolve: (() => void) | null
  _setReadStateCallbacksPromise: Promise<void>
  canCreateBackendOrphanWidgets = false

  constructor(core: IClient, json?: InstantJSON | null) {
    this._core = core
    this._json = json ? filterFalsyInstantJSONEntries(json) : null
    this._setReadStateCallbacksPromise = new Promise(resolve => {
      this._setReadStateCallbacksPromiseResolve = resolve
    })
  }

  async load(): Promise<StandaloneProvider> {
    this._state = this._state.set('isLoaded', true)

    // When the provider was instantiated with a JSON serialization, we create the annotations
    // and form fields (so there are no orphan widgets) in the loading step.

    // If Form Creator is not available, we have to load form field values here
    !this._formFieldCallbacks && (await this._loadFormFieldValues())

    if (!this._json) {
      return this
    }

    // Update Core document with InstantJSON data
    await this._core.importInstantJSON({
      ...instantJSONStub,
      ...this._json,
    } as InstantJSON)

    invariant(this._json)

    const { annotations, attachments } = this._json

    if (this._isDestroyed() || !attachments || Object.entries(attachments).length === 0) {
      return this
    }

    // Create instantJSON attachments
    if (annotations) {
      for (let i = 0; i < annotations.length; i++) {
        let attachmentBlob: Blob | null = null

        const annotation = annotations[i]

        if ('imageAttachmentId' in annotation && annotation.imageAttachmentId) {
          const attachmentInfo = attachments ? attachments[annotation.imageAttachmentId] : null

          if (attachmentInfo) {
            try {
              attachmentBlob = binaryImageToBlob(
                atob(attachmentInfo.binary),
                attachmentInfo.contentType,
              )
              invariant(this._annotationCallbacks)

              this._annotationCallbacks.createAttachment(
                annotation.imageAttachmentId,
                attachmentBlob,
              )
            } catch (error) {
              info(
                `Skipped attachment with id ${annotation.imageAttachmentId} from payload because an error occurred while converting the binary image to blob.`,
              )
              info(error)
            }
          }
        }
      }
    }

    return this
  }

  destroy(): void {
    this._state = this._state.set('isDestroyed', true)
    this._annotationCallbacks = null
    this._readStateCallbacks = null
    this._bookmarkCallbacks = null
    this._formFieldCallbacks = null
    this._formFieldValueCallbacks = null
    this._commentCallbacks = null
  }

  setReadStateCallbacks(readStateCallbacks: ReadStateProviderCallbacks) {
    this._readStateCallbacks = readStateCallbacks

    this._setReadStateCallbacksPromiseResolve?.()
  }

  setAnnotationCallbacks(annotationCallbacks: AnnotationProviderCallbacks) {
    this._annotationCallbacks = annotationCallbacks
  }

  setBookmarkCallbacks(bookmarkCallbacks: BookmarkProviderCallbacks) {
    this._bookmarkCallbacks = bookmarkCallbacks
  }

  setFormFieldCallbacks(formFieldCallbacks: FormFieldProviderCallbacks) {
    this._formFieldCallbacks = formFieldCallbacks
  }

  setFormFieldValueCallbacks(formFieldValueCallbacks: FormFieldValueCallbacks) {
    this._formFieldValueCallbacks = formFieldValueCallbacks
  }

  setCommentCallbacks(commentCallbacks: CommentProviderCallbacks) {
    this._commentCallbacks = commentCallbacks
  }

  createComment(_comment: Comment, allComments: List<Comment>, annotations: Map<ID, Annotation>) {
    return this._core.applyComments(
      allComments.map(comment => serializeWithProperRootId(comment, annotations)).toArray(),
    )
  }

  updateComment(_comment: Comment, allComments: List<Comment>, annotations: Map<ID, Annotation>) {
    return this._core.applyComments(
      allComments.map(comment => serializeWithProperRootId(comment, annotations)).toArray(),
    )
  }

  deleteComment(_commentId: string, allComments: List<Comment>, annotations: Map<ID, Annotation>) {
    return this._core.applyComments(
      allComments.map(comment => serializeWithProperRootId(comment, annotations)).toArray(),
    )
  }

  async loadComments(): Promise<void> {
    // If a previous call is in flight, return the current promise.
    if (this._commentsLoadedPromise) {
      return this._commentsLoadedPromise
    }

    this._commentsLoadedPromise = this._loadComments()

    return this._commentsLoadedPromise
  }

  async _loadComments(): Promise<void> {
    this._verifyLoaded()

    const comments: CommentJSON[] = (await this._core.getComments()) ?? []

    const parsedComments = List(
      comments.map(comment => {
        let id: string

        if (comment.pdfObjectId) {
          id = comment.id || comment.pdfObjectId?.toString()
        } else {
          // This should never happen as every annotation from Core
          // comes with a pdfObjectId. However, in case removing it breaks it,
          // we keep it here for now.
          if (process.env.NODE_ENV === 'development') {
            throw new PSPDFKitError(
              `Received an initial comment entry without a pdfObjectId: ${JSON.stringify(
                comment,
                null,
                2,
              )}`,
            )
          }

          id = generateAnnotationId()
        }

        return deserializeComment(id, comment)
      }),
    )

    await Promise.all(
      parsedComments
        .map(
          comment =>
            typeof comment.pageIndex === 'number' &&
            this.loadAnnotationsForPageIndex(comment.pageIndex),
        )
        .filter(Boolean)
        .toArray(),
    )

    this._commentCallbacks?.createComments(parsedComments, CREATE_REASON_LOAD)

    this._commentsLoadedPromise = Promise.resolve()
  }

  updateTabOrderTimeout: ReturnType<typeof setTimeout> | null = null
  pagesTabOrderToUpdate: Set<number> = Set()

  async updateTabOrder(pageIndex: number): Promise<void> {
    this.pagesTabOrderToUpdate = this.pagesTabOrderToUpdate.add(pageIndex)

    if (this.updateTabOrderTimeout) {
      clearTimeout(this.updateTabOrderTimeout)
    }

    this.updateTabOrderTimeout = setTimeout(async () => {
      const pagesTabOrderToUpdate = this.pagesTabOrderToUpdate.toArray()

      this.pagesTabOrderToUpdate = Set()

      if (this._isDestroyed()) {
        return
      }

      const tabOrders = await Promise.all(
        pagesTabOrderToUpdate.map(pageIndex => this._core.getTabOrder(pageIndex)),
      )

      if (this._isDestroyed()) {
        return
      }

      invariant(this._annotationCallbacks)

      batch(() => {
        pagesTabOrderToUpdate.forEach((pageIndex, index) => {
          this._annotationCallbacks?.setPageTabOrder(pageIndex, tabOrders[index])
        })
      })
    }, 1000)
  }

  async setTabOrder(pageIndex: number, tabOrder: Array<TabOrderIdsEntry>): Promise<void> {
    return this._core.setTabOrder(pageIndex, tabOrder)
  }

  async createAnnotation(
    annotation: AnnotationsUnion,
    attachments: Map<string, Attachment>,
  ): Promise<void> {
    this._verifyLoaded()

    const attachment = attachments.find((_attachment: Attachment, imageAttachmentId: string) => {
      invariant('imageAttachmentId' in annotation, 'Annotation must have imageAttachmentId.')

      return imageAttachmentId === annotation.imageAttachmentId
    })

    const newPdfObjectId = await this._core.createAnnotation(
      serializeAnnotation(annotation),
      attachment ? attachment.data : null,
    )

    if (
      typeof newPdfObjectId === 'number' &&
      typeof annotation.pdfObjectId === 'number' &&
      annotation.pdfObjectId !== newPdfObjectId &&
      !this._isDestroyed()
    ) {
      invariant(this._annotationCallbacks)

      this._annotationCallbacks.updateAnnotations(
        List([annotation.set('pdfObjectId', newPdfObjectId)]),
      )
    }

    await this.updateTabOrder(annotation.pageIndex)
  }

  async updateAnnotation(annotation: AnnotationsUnion) {
    this._verifyLoaded()

    await this._core.updateAnnotation(serializeAnnotation(annotation))

    await this.updateTabOrder(annotation.pageIndex)
  }

  deleteAnnotation(annotation: AnnotationsUnion): Promise<void> {
    this._verifyLoaded()

    // Core.js needs id and pdfObjectId, if present, to be able to delete both original and new annotations.
    return this._core.deleteAnnotation(
      serializeAnnotation(annotation) as AnnotationsBackendJSONUnion & { pdfObjectId: number },
    )
  }

  createBookmark(bookmark: Bookmark): Promise<void> {
    this._verifyLoaded()

    return this._core.createBookmark(serializeBookmark(bookmark))
  }

  updateBookmark(bookmark: Bookmark): Promise<void> {
    this._verifyLoaded()

    return this._core.updateBookmark(serializeBookmark(bookmark))
  }

  deleteBookmark(bookmarkId: BookmarkID): Promise<void> {
    this._verifyLoaded()

    return this._core.deleteBookmark(bookmarkId)
  }

  createFormField(formField: FormField): Promise<void> {
    this._verifyLoaded()

    invariant(this._readStateCallbacks)

    const formFieldWidgets = this._readStateCallbacks.getFormFieldWidgets(formField)

    return this._core
      .createFormField(
        serializeFormField(formField),
        formFieldWidgets.map(widget => serializeAnnotation(widget)).toArray(),
      )
      .then(async newPdfObjectIds => {
        batch(() => {
          newPdfObjectIds.forEach((newPdfObjectId, index) => {
            const widget = formFieldWidgets.get(index)

            invariant(widget)
            invariant(this._annotationCallbacks)

            // Update Redux button widgets object ID to make sure
            // new button import icons render the image
            if (
              typeof newPdfObjectId === 'number' &&
              typeof widget.pdfObjectId === 'number' &&
              widget.pdfObjectId !== newPdfObjectId &&
              !this._isDestroyed()
            ) {
              this._annotationCallbacks.updateAnnotations(
                List([widget.set('pdfObjectId', newPdfObjectId)]),
              )
            }
          })
        })
      })
  }

  updateFormField(formField: FormField): Promise<void> {
    this._verifyLoaded()

    invariant(this._readStateCallbacks)

    const formFieldWidgets = this._readStateCallbacks.getFormFieldWidgets(formField)

    return this._core.updateFormField(
      serializeFormField(formField),
      formFieldWidgets.map(widget => serializeAnnotation(widget)).toArray(),
    )
  }

  deleteFormField(formField: FormField): Promise<void> {
    this._verifyLoaded()

    // Core.js needs id and pdfObjectId, if present, to be able to delete both original and new form fields.
    return this._core.deleteFormField(serializeFormField(formField))
  }

  // This is called directly when using instance.getFormFields() or whenever loadAnnotationsForPageIndex
  // is called.
  loadFormFields(): Promise<void> {
    // If a previous call is in flight, return the current promise.
    if (this._formFieldsLoadedPromise) {
      return this._formFieldsLoadedPromise
    }

    this._formFieldsLoadedPromise = this._loadFormFields()

    return this._formFieldsLoadedPromise
  }

  async _loadFormFields(): Promise<void> {
    this._verifyLoaded()

    const formObjects = await this._core.readFormJSONObjects()

    // the provider may have been destroyed while forms were being loaded,
    // in that case we bail out.
    if (this._isDestroyed()) {
      return
    }

    let annotationAdditions: List<WidgetAnnotation> = List()
    let formFieldAdditions: List<FormField> = List().withMutations(mutableAdditions => {
      formObjects.forEach(json => {
        // We need to retrieve the associated widgets too, as they're not included in the
        // annotations list.
        const { formField: formFieldJSON, widgets: widgetsJSON, value } = json

        try {
          let id

          if (formFieldJSON.pdfObjectId) {
            id = formFieldJSON.pdfObjectId.toString()
          } else {
            // FIXME(miguel): this should never happen as every form field from Core
            // comes with a pdfObjectId. However, in case removing it breaks it,
            // we keep it here for now.
            if (process.env.NODE_ENV === 'development') {
              throw new PSPDFKitError(
                `Received an initial form field without a pdfObjectId: ${JSON.stringify(
                  formFieldJSON,
                  null,
                  2,
                )}`,
              )
            }

            id = generateAnnotationId()
          }

          const formField = deserializeFormField(id, formFieldJSON as FormFieldJSON)

          invariant(this._readStateCallbacks)

          if (!this._readStateCallbacks.isFormFieldInState(formField.name)) {
            mutableAdditions.push(formField.set('value', value))
          }

          widgetsJSON.forEach(widgetJSON => {
            let id

            if (widgetJSON.pdfObjectId) {
              id = widgetJSON.id || widgetJSON.pdfObjectId.toString()
            } else {
              // TODO @miguelcalderon : this should never happen as every annotation from Core
              // comes with a pdfObjectId. However, in case removing it breaks it,
              // we keep it here for now.
              if (process.env.NODE_ENV === 'development') {
                throw new PSPDFKitError(
                  `Received an initial widget annotation without a pdfObjectId: ${JSON.stringify(
                    widgetJSON,
                    null,
                    2,
                  )}`,
                )
              }

              id = generateAnnotationId()
            }

            invariant(this._readStateCallbacks)

            annotationAdditions = annotationAdditions.push(deserializeAnnotation(id, widgetJSON))
          })
        } catch (error) {
          info(
            `Skipped creating form field #${formFieldJSON.pdfObjectId} from payload because an error occurred while deserializing.`,
          )
          info(error)
        }
      })
    })

    const coreFormFieldsToUpdate = {}

    // Regenerate duplicate annotation ids.
    const annotationIdDict = {}
    annotationAdditions.forEach(annotation => {
      if (!annotationIdDict[annotation.id]) {
        annotationIdDict[annotation.id] = []
      }

      annotationIdDict[annotation.id].push(annotation.pdfObjectId)
    })

    annotationAdditions = annotationAdditions.map(annotation => {
      const annotations = annotationIdDict[annotation.id].filter(
        pdfObjectId => pdfObjectId !== annotation.pdfObjectId,
      )

      if (
        (annotations.length > 0 && annotation.pdfObjectId?.toString() !== annotation.id) ||
        this._readStateCallbacks?.isAnnotationInState(annotation.id)
      ) {
        const newAnnotationId = generateAnnotationId()

        if (coreFormFieldsToUpdate[annotation.formFieldName]) {
          coreFormFieldsToUpdate[annotation.formFieldName].push({
            [annotation.id]: newAnnotationId,
          })
        } else {
          coreFormFieldsToUpdate[annotation.formFieldName] = [{ [annotation.id]: newAnnotationId }]
        }

        formFieldAdditions = formFieldAdditions.map(addition => {
          if (addition.name === annotation.formFieldName) {
            return addition.update('annotationIds', annotationIds =>
              annotationIds?.map(id => (id === annotation.id ? newAnnotationId : id)),
            )
          }

          return addition
        })

        return annotation.set('id', newAnnotationId)
      }

      return annotation
    })

    Object.keys(coreFormFieldsToUpdate).forEach(formFieldName => {
      const formField = formFieldAdditions.find(addition => addition.name === formFieldName)

      invariant(formField)

      const widgets = annotationAdditions
        .filter(annotation => annotation.formFieldName === formFieldName)
        .toArray()
        .map(widget => serializeAnnotation(widget))

      this._core.updateFormField(serializeFormField(formField as FormField), widgets)
    })

    // Create form fields and form field values first, before annotations,
    // so widgets AP streams are not invalidated when the form field value is first set.
    if (formFieldAdditions.size > 0 && !this._isDestroyed()) {
      invariant(this._formFieldCallbacks)

      this._formFieldCallbacks.createFormFields(formFieldAdditions, CREATE_REASON_LOAD)
    }

    // Once we have loaded form fields, we can load form field values.
    await this._loadFormFieldValues()

    // Since all widget annotations from the document are available now, create them independently
    // of the pages for which the rest of the annotations have already been loaded.
    if (annotationAdditions.size > 0 && !this._isDestroyed()) {
      invariant(this._annotationCallbacks)

      this._annotationCallbacks.createAnnotations(annotationAdditions, Map(), CREATE_REASON_LOAD)
    }

    this._formFieldsLoadedPromise = Promise.resolve()
  }

  createFormFieldValue(formFieldValue: FormFieldValue): Promise<void> {
    this._verifyLoaded()

    return this.setFormFieldValue(formFieldValue)
  }

  setFormFieldValue(formFieldValue: FormFieldValue): Promise<void> {
    this._verifyLoaded()

    return this._core.setFormFieldValue(serializeFormFieldValue(formFieldValue))
  }

  deleteFormFieldValue(formFieldValueID: string): Promise<void> {
    this._verifyLoaded()

    return this._core.deleteFormFieldValue(formFieldValueID.replace('form-field-value/', ''))
  }

  loadAnnotationsForPageIndex(pageIndex: number): Promise<void> {
    const alreadyLoadedPagesPromise = this._state.alreadyLoadedPages.get(pageIndex)

    if (alreadyLoadedPagesPromise) {
      return alreadyLoadedPagesPromise
    }

    const annotationsPromise = this._loadAnnotationsForPageIndex(pageIndex)

    // We save the promise so that if `loadAnnotationsForPageIndex` is called again
    // before the promise resolves the new calls awaits for the promise as well.
    this._state = this._state.setIn(['alreadyLoadedPages', pageIndex], annotationsPromise)

    return annotationsPromise
  }

  async _loadAnnotationsForPageIndex(pageIndex: number): Promise<void> {
    this._verifyLoaded()

    // These annotations can include variant information.
    const [annotationsWithVariants, pageAnnotationsTabOrder] = await Promise.all([
      this._core.annotationsForPageIndex(pageIndex),
      this._core.getTabOrder(pageIndex),
    ])

    // the current provider may have been destroyed while annotations were being loaded,
    // in that case we bail out.
    if (this._isDestroyed()) {
      return
    }

    const APStreamVariantsRollover = [] as number[]
    const APStreamVariantsDown = [] as number[]

    // Extract any existing variants data from the annotations data
    const annotations = annotationsWithVariants
      .map(({ rollover, down, ...annotation }) => {
        if (rollover && typeof annotation.pdfObjectId === 'number') {
          APStreamVariantsRollover.push(annotation.pdfObjectId)
        }

        if (down && typeof annotation.pdfObjectId === 'number') {
          APStreamVariantsDown.push(annotation.pdfObjectId)
        }

        return annotation
      })
      // Remove dummy annotations which only held variant information; can be identified by
      // the lack of a pageIndex.
      .filter(annotation => typeof annotation.pageIndex === 'number')

    // Only call loadFormFields when form design is enabled (otherwise getFormJSON()
    // is used to retrieve forms data).
    this._formFieldCallbacks && (await this.loadFormFields())

    const additions = List().withMutations(mutableAdditions => {
      annotations // Filter out annotations already in the frontend state
        .filter(
          json =>
            !json.id ||
            (this._readStateCallbacks && !this._readStateCallbacks.isAnnotationInState(json.id)),
        )
        .forEach(json => {
          // TODO @miguelcalderon : this should never happen as every annotation from Core
          // comes with a pdfObjectId. However, in case removing it breaks it,
          // we keep it here for now.
          if (typeof json.pdfObjectId !== 'number' && process.env.NODE_ENV === 'development') {
            throw new PSPDFKitError(
              `Received an initial annotation without a pdfObjectId: ${JSON.stringify(
                json,
                null,
                2,
              )}`,
            )
          }

          try {
            let id: string | undefined

            if (isExtractedLinkAnnotation(json)) {
              // All extracted link annotations have pdfObjectId set to 0, so it cannot be
              // used as a string for `id`, which need to be unique and thus are generated instead.
              id = json.id || generateAnnotationId()
            } else {
              id = json.id || json.pdfObjectId.toString()
            }

            // Is the annotation ID already in the state or in the additions?
            if (
              mutableAdditions.some(annotation => annotation.id === id) ||
              this._readStateCallbacks?.isAnnotationInState(id)
            ) {
              // In that case, regenerate the ID.
              id = generateAnnotationId()

              json.id = id

              // Keep the Core document up to date.
              this._core.updateAnnotation(json)
            }

            const annotation = deserializeAnnotation(id, json)

            mutableAdditions.push(annotation)
          } catch (error) {
            info(
              `Skipped creating annotation #${json.pdfObjectId} from payload because an error occurred while deserializing.`,
            )
            info(error)
          }
        })
    })

    batch(() => {
      invariant(this._annotationCallbacks)

      if (additions.size > 0) {
        this._annotationCallbacks.createAnnotations(additions, Map(), CREATE_REASON_LOAD)
      }

      this._annotationCallbacks.setPageTabOrder(pageIndex, pageAnnotationsTabOrder)

      if (APStreamVariantsRollover.length > 0) {
        this._annotationCallbacks.addAnnotationVariants('rollover', APStreamVariantsRollover)
      }

      if (APStreamVariantsDown.length > 0) {
        this._annotationCallbacks.addAnnotationVariants('down', APStreamVariantsDown)
      }
    })

    // At this point we don't need a reference to the original promise anymore.
    this._state = this._state.setIn(['alreadyLoadedPages', pageIndex], Promise.resolve())
  }

  // This method is called once when `load`ing the StandaloneProvider. It will initialize the form
  // field value state. Thus, it loads the form values from Core, including those from the imported
  // Instant JSON.
  async _loadFormFieldValues(): Promise<void> {
    this._verifyLoaded()

    const response = await this._core.getFormValues()

    // the provider may have been destroyed while form field values were being loaded,
    // in that case we bail out.
    if (this._isDestroyed()) {
      return
    }

    const formFieldValues = List().withMutations(mutableFormFieldValues => {
      response.forEach(json => {
        try {
          mutableFormFieldValues.push(deserializeFormFieldValue(json))
        } catch (error) {
          info(
            `Skipped creating form field value #${json.pdfObjectId} from payload because an error occurred while deserializing.`,
          )
          info(error)
        }
      })
    })

    if (formFieldValues.size > 0 && !this._isDestroyed()) {
      invariant(this._formFieldValueCallbacks)

      this._formFieldValueCallbacks.setFormFieldValues(formFieldValues)
    }
  }

  async loadBookmarks(): Promise<void> {
    this._verifyLoaded()

    const response = await this._core.getBookmarks()

    // the provider may have been destroyed while bookmarks were being loaded,
    // in that case we bail out.
    if (this._isDestroyed()) {
      return
    }

    const bookmarks = List().withMutations(mutableBookmarks => {
      response.forEach(json => {
        let id

        if (json.id) {
          id = json.id
        } else if (json.pdfBookmarkId) {
          id = json.pdfBookmarkId
        } else {
          if (process.env.NODE_ENV === 'development') {
            throw new PSPDFKitError(
              `Received an initial bookmark without a pdfBookmarkId: ${JSON.stringify(
                json,
                null,
                2,
              )}`,
            )
          }

          id = generateBookmarkId()
        }

        try {
          mutableBookmarks.push(deserializeBookmark(id, json))
        } catch (error) {
          info(
            `Skipped creating bookmark #${id} from payload because an error occurred while deserializing.`,
          )
          info(error)
        }
      })
    })

    if (bookmarks.size > 0 && !this._isDestroyed()) {
      invariant(this._bookmarkCallbacks)

      this._bookmarkCallbacks.createBookmarks(bookmarks, CREATE_REASON_LOAD)
    }
  }

  _verifyLoaded() {
    invariant(this._state.isLoaded, 'StandaloneProvider not properly initialized.')
  }

  _isDestroyed(): boolean {
    return this._state.isDestroyed
  }

  async syncChanges(): Promise<void> {}
}

function isExtractedLinkAnnotation(annotation: IObject): boolean {
  return annotation.type === 'pspdfkit/link' && annotation.pdfObjectId === 0
}

function serializeWithProperRootId(comment: Comment, annotations: Map<ID, Annotation>) {
  invariant(comment.rootId, 'A new comment must have `rootId` present')

  const rootAnnotation = annotations.get(comment.rootId)

  invariant(rootAnnotation, 'An annotation must be present linked to the comment to create')

  // The annotation should be serialized using a numeric value as its `rootId` if the
  // `pdfObjectId` of the root annotation matches its `id`. This is necessary because
  // when `apply_comments` is called in Core, if a numeric value is used for `rootId`,
  // Core will consider it to be the annotation's `pdfObjectId` instead of its
  // Instant ID. This is important because the original Instant ID of the
  // root annotation for comments is replaced by its `pdfObjectId` in the
  // _loadAnnotationsForPageIndex method of this Standalone Provider, thus Core
  // won't be able to match the annotation correctly if we leave the `rootId` as a
  // string.

  return serializeComment(
    comment,
    rootAnnotation.pdfObjectId?.toString() === rootAnnotation.id
      ? parseInt(comment.rootId)
      : comment.rootId,
  )
}
