  getPDFURL({ includeComments = true, saveForPrinting, excludeAnnotations }: GetPDFURLFlags = {}): {
    promise: Promise<string>
    revoke: IFunction
  } {
    return this.generatePDFObjectURL({
      includeComments,
      saveForPrinting,
      excludeAnnotations,
    })
  }

  generatePDFObjectURL({
    includeComments = true,
    saveForPrinting,
    excludeAnnotations = false,
  }: GeneratePDFObjectURLFlags = {}): {
    promise: Promise<string>
    revoke: IFunction
  } {
    let objectUrl,
      isRevoked = false
    const promise = new Promise<string>(resolve => {
      this.exportPDF({
        flatten: true,
        includeComments,
        saveForPrinting,
        excludeAnnotations,
      }).then(arrayBuffer => {
        if (isRevoked) {
          return
        }

        const blob = new Blob([arrayBuffer], {
          // @ts-expect-error
          type: arrayBuffer.mimeType,
        })

        objectUrl = window.URL.createObjectURL(blob)
        resolve(objectUrl)
      })
    })

    return {
      promise,
      revoke: () => {
        if (objectUrl) {
          window.URL.revokeObjectURL(objectUrl)
        }

        isRevoked = true
      },
    }
  }

