  async setSignaturesLTV(certificates?: ArrayBuffer[] | string[]) {
    try {
      const base64CertificateArray: string[] = (certificates ?? []).map(
        (certificate: string | ArrayBuffer): string => {
          if (certificate instanceof ArrayBuffer) {
            return Base64.fromUint8Array(new Uint8Array(certificate))
          }

          return Base64.encode(certificate)
        },
      )

      const revocationResponses = await this.getRevocationResponses(base64CertificateArray)

      const signaturesInfo = await this.client
        .setSignaturesLTV(revocationResponses)
        .then(signaturesInfoResponse => deserializeSignaturesInfo(signaturesInfoResponse))

      if (
        signaturesInfo.signatures?.find(
          signature =>
            signature.certificateChainValidationStatus ===
            CertificateChainValidationStatus.ok_but_could_not_check_revocation,
        )
      ) {
        throw 'Could not set LTV for all signatures. Check that the OCSP response is valid.'
      }

      // We clear the signature info promise as it could have changed with the new LTV information.
      this._state = this._state.set('signaturesInfoPromise', null)

      return this.getSignaturesInfo()
    } catch (e) {
      throw new PSPDFKitError(`Setting signatures LTV failed: ${e}`)
    }
  }

  getSignaturesInfo() {
    try {
      if (this._state.signaturesInfoPromise) {
        return this._state.signaturesInfoPromise
      }

      const signaturesInfoPromise = this.client
        .getSignaturesInfo()
        .then(signaturesInfoResponse => deserializeSignaturesInfo(signaturesInfoResponse))

      // We save the promise so that if `getSignaturesInfo()` is called again
      // before the promise resolves the new calls awaits for the promise as well!
      this._state = this._state.set('signaturesInfoPromise', signaturesInfoPromise)

      return signaturesInfoPromise
    } catch (e) {
      throw new PSPDFKitError(`Getting document signatures info: ${e}`)
    }
  }

  async refreshSignaturesInfo(): Promise<void> {
    this._state = this._state.set('signaturesInfoPromise', null)
  }

