import { invariant, warn } from '@pspdfkit/shared'
import { List } from 'immutable'

import { JSONToAction, actionToJSON } from './action'
import { JSONToColor, colorToJSON } from './color'
import { OutlineElement } from '../../models'

import type { Color } from '../../models'
import type { OutlineJSON } from '@pspdfkit/core'

export function toJSON(outlineElement: OutlineElement): OutlineJSON {
  return {
    type: 'pspdfkit/outline-element',
    children: outlineElement.children && outlineElement.children.map(child => toJSON(child)).toJS(),
    title: outlineElement.title,
    color: outlineElement.color && colorToJSON(outlineElement.color as Color),
    isBold: outlineElement.isBold,
    isItalic: outlineElement.isItalic,
    isExpanded: outlineElement.isExpanded,
    action: outlineElement.action && actionToJSON(outlineElement.action),
  }
}

export function fromJSON(json: OutlineJSON): OutlineElement {
  invariant(json.type === 'pspdfkit/outline-element', 'invalid outline element type.')
  invariant(
    json.children == null || Array.isArray(json.children),
    'children must be an Array<OutlineElement>.',
  )
  invariant(typeof json.title == 'string', 'title must be a string.')
  invariant(json.isBold == null || typeof json.isBold == 'boolean', 'isBold must be a boolean.')
  invariant(
    json.isItalic == null || typeof json.isItalic == 'boolean',
    'isItalic must be a boolean.',
  )
  invariant(
    json.isExpanded == null || typeof json.isExpanded == 'boolean',
    'isExpanded must be a boolean.',
  )

  let action

  try {
    action = json.action && JSONToAction(json.action)
  } catch (error) {
    // eslint-disable-next-line no-console
    warn(`PDF Action not supported ${JSON.stringify(json.action)})`)
  }

  let color

  try {
    color = json.color && JSONToColor(json.color)
  } catch (error) {
    // eslint-disable-next-line no-console
    warn(`Invalid color:

${json.color}`)
  }

  const deserialized = {
    title: json.title,
    color,
    isBold: json.isBold === true,
    isItalic: json.isItalic === true,
    isExpanded: json.isExpanded === true,
    action,
    children: List(),
  }

  if (json.children && json.children.length > 0) {
    deserialized.children = List(json.children.map(fromJSON))
  }

  return new OutlineElement(deserialized)
}
