import { Map } from 'immutable'
import { invariant } from '@pspdfkit/shared'

import { FormFieldValue, SignatureFormField, WidgetAnnotation } from '@/models'
import {
  isCacheableAnnotationAPStream,
  stringifyAnnotationVisualProperties,
} from '@/utils/annotation'
import ImageHandle from '@/lib/handles/ImageHandle'
import { areStampAPStreamsIdentical } from '@/utils/stamp'

import type { Size } from '@/models'
import type { AnnotationsUnion } from '@/typings/serializers'
import type { ID } from '@/models/annotations/Annotation'
import type { IAnnotationVariant } from '@/enums/AnnotationVariant'
import type { Set } from 'immutable'
import type { Backend } from '@/typings/backend'
import type { IFunction } from '@/typings/utils'
import type { CoreAnnotationVariant } from '@pspdfkit/core'
import type { DiscardablePromise } from '@/utils/promise'
import type { StampAnnotation } from '@/models/annotations'

export type AnnotationImageHandle = ImageHandle<HTMLImageElement | HTMLCanvasElement>

type AnnotationVariantsImageHandles = Record<CoreAnnotationVariant, AnnotationImageHandle>
export type APStream = AnnotationImageHandle | AnnotationVariantsImageHandles

export type AttachmentsCacheKey = `${string}_${string}`

export type AttachmentMetadataEntry = {
  dimensions: Size
  img: HTMLImageElement | HTMLCanvasElement
  prevRotation: number
  zoomLevel?: number | undefined
  provisional?: boolean
}

/**
 * SharedBackend
 *
 * This class contains code that can be reused by both StandaloneBackend and SharedBackend, which extend it.
 *
 * Methods and instance variables that are identical in both backends can be moved here so as to reduce
 * the amount of moving parts and therefore the chance for errors.
 */
export class SharedBackend {
  // Cached images for attachments.
  attachmentsCache: Map<AttachmentsCacheKey, AttachmentMetadataEntry> = Map()

  cachedAPStreams: Map<number, Map<ID, APStream>> = Map()
  pageAPStreamsPromises: Map<number, Promise<void>> = Map()
  annotationAPStreamPromises: Map<ID, (arg0: AnnotationImageHandle | null | undefined) => void> =
    Map()
  // Stores the last rendered stamp annotation AP stream
  // so it can be reused with other visually identical annotations.
  _cachedRenderedAnnotation: {
    index: string
    width: number
    height: number
    APStreamPromise: Promise<ImageHandle<HTMLImageElement> | undefined>
  } | null = null

  // Keeps a count of the number of AP streams using specific object URLs
  // so they're not released if they're still being used.
  _objectURLs: Record<string, number> = {}

  _makeEnqueuedRelease = (
    imageHandle: ImageHandle<HTMLImageElement | HTMLCanvasElement> | null,
    imageHandleIndex: string,
  ) => {
    if (imageHandle?.element?.tagName === 'IMG') {
      const url = (imageHandle.element as HTMLImageElement).src

      if (!url) {
        return
      }

      if (typeof this._objectURLs[url] === 'number') {
        this._objectURLs[url]++
      } else {
        this._objectURLs[url] = 1
      }

      const originalRelease = imageHandle.release

      imageHandle.release = () => {
        this._objectURLs[url]--

        if (this._objectURLs[url] <= 0) {
          originalRelease?.()

          if (this._cachedRenderedAnnotation?.index === imageHandleIndex) {
            this._cachedRenderedAnnotation = null
          }

          delete this._objectURLs[url]
        }
      }
    }
  }

  getAnnotationFormFieldAndValue(annotation: AnnotationsUnion) {
    const provider = (this as any as Backend).provider

    invariant(
      provider instanceof provider.constructor,
      'Backend can only use backend annotation provider',
    )

    // For widget annotations, we need the associated form field to render the widget with the current value.
    const formField =
      annotation instanceof WidgetAnnotation
        ? provider._readStateCallbacks?.getFormFieldByName(annotation.formFieldName)
        : null
    const formFieldValue =
      formField && !(formField instanceof SignatureFormField)
        ? new FormFieldValue({
            name: formField.name,
            // We will not be running JS when rendering the widget, so we pass the
            // formatted value if available.
            value:
              typeof formField.formattedValue !== 'undefined'
                ? formField.formattedValue
                : typeof formField.value === 'string'
                ? formField.value
                : formField.values,
          })
        : null

    return { formField, formFieldValue }
  }

  getAnnotationAvailableVariants(annotation: AnnotationsUnion) {
    const provider = (this as any as Backend).provider

    invariant(
      provider instanceof provider.constructor,
      'Backend can only use backend annotation provider',
    )
    // Some annotations can have different appearances for different states. In order to improve UX, all
    // variants are rendered and cached at the same time.
    const annotationAvailableVariants =
      provider._readStateCallbacks?.getAvailableVariants(annotation) || []
    const availableVariants: CoreAnnotationVariant[] = [...annotationAvailableVariants, 'normal']

    return availableVariants
  }

  /**
   * Processes a renderAnnotation request with the following rules:
   *
   * - If the annotation AP stream is non-cacheable, it calls renderAnnotation() right away.
   * - If the annotation AP stream is cacheable, it waits for the page AP streams to be available if needed.
   * - If the AP stream is available it resolves with it. Otherwise, it calls renderAnnotation().
   */
  cachedRenderAnnotation(
    annotation: AnnotationsUnion,
    blob: Blob | null | undefined,
    width: number,
    height: number,
    variant?: IAnnotationVariant,
  ): {
    promise: Promise<AnnotationImageHandle | null | undefined>
    cancel: IFunction
  } {
    const provider = (this as any as Backend).provider

    invariant(
      provider instanceof provider.constructor,
      'Backend can only use backend annotation provider',
    )

    const { formField, formFieldValue } = this.getAnnotationFormFieldAndValue(annotation)

    // images, stamps, unknown annotation types and signature widgets AP streams are not cached in the backend instance.
    if (!isCacheableAnnotationAPStream(annotation, formField)) {
      return (this as unknown as Backend).renderAnnotation(
        annotation,
        formFieldValue,
        blob,
        width,
        height,
        variant,
      )
    }

    const availableVariants = this.getAnnotationAvailableVariants(annotation)

    let cancelled = false

    let cancelPromise = () => {
      cancelled = true
    }

    return {
      // eslint-disable-next-line no-async-promise-executor
      promise: new Promise(async (resolve, reject) => {
        const cleanResolve = imageHandle => {
          // Instead of just resolving with the image handle, we first delete the registered
          // resolve callback from the backend promise resolve map.
          const annotationAPStreamPromiseResolve = this.annotationAPStreamPromises.get(
            annotation.id,
          )

          if (annotationAPStreamPromiseResolve) {
            this.annotationAPStreamPromises = this.annotationAPStreamPromises.delete(annotation.id)
            annotationAPStreamPromiseResolve(imageHandle)
          }
        }

        // Check if a previous renderAnnotation() request is waiting.
        const annotationAPStreamPromiseResolve = this.annotationAPStreamPromises.get(annotation.id)

        // Register the new resolve callback.
        this.annotationAPStreamPromises = this.annotationAPStreamPromises.set(
          annotation.id,
          resolve,
        )

        // Resolve any previous request with null to prevent the calling image component from stalling.
        if (annotationAPStreamPromiseResolve) {
          annotationAPStreamPromiseResolve(null)
        }

        try {
          // Retrieve the current page's AP streams render promise.
          const pageAPStreamsPromise = this.pageAPStreamsPromises.get(annotation.pageIndex)

          if (!pageAPStreamsPromise) {
            // If the promise is not available, it means that renderPageAnnotations() has not been called yet
            // for this page. Therefore we register the resolve callback so it gets called when renderPageAnnotations()
            // is called and resolves.
            const annotationAPStreamPromise = new Promise(resolve => {
              this.annotationAPStreamPromises = this.annotationAPStreamPromises.set(
                annotation.id,
                resolve,
              )
            })

            // Wait for the registered resolve callback to be called.
            const imageHandle = (await annotationAPStreamPromise) as AnnotationImageHandle

            resolve(imageHandle)

            return
          } else {
            // Wait for the page AP streams to be available.
            await pageAPStreamsPromise
          }

          const cachedPageAPStreams = this.cachedAPStreams.get(annotation.pageIndex)

          // Are there already cached AP streams for this page?
          if (cachedPageAPStreams) {
            // Is there already a cached AP stream for the annotation?
            const cachedAPStream = cachedPageAPStreams
              ? cachedPageAPStreams.get(annotation.id)
              : null

            if (cachedAPStream) {
              // Then resolve with the cached AP stream
              cleanResolve(this.getAPStream(cachedAPStream, variant))

              return
            }
          }

          // In any other case, render the annotation.
          const { promise, cancel } = this.renderAPStream(
            annotation,
            formFieldValue,
            blob,
            width,
            height,
            availableVariants,
            variant,
          )

          if (cancelled) {
            cleanResolve(null)
          } else {
            cancelPromise = cancel

            if (availableVariants.length > 1) {
              const APStreams = await Promise.all(
                (promise as DiscardablePromise<AnnotationImageHandle>[]).map(p => p.promise),
              )

              const imageHandle = APStreams[availableVariants.indexOf(variant || 'normal')]

              cleanResolve(imageHandle)

              if (APStreams.some(Boolean)) {
                this.cacheAPStream(
                  availableVariants.reduce(
                    (acc, availableVariant, index) =>
                      // We only want to cache the AP stream if it's not null,
                      // otherwise subsequent APStream rendering may fail.
                      APStreams[index]
                        ? {
                            ...acc,
                            [availableVariant]: APStreams[index],
                          }
                        : acc,
                    {},
                  ) as APStream,
                  annotation,
                )
              }
            } else {
              const APStream = (await promise) as AnnotationImageHandle

              const imageHandle = APStream ? this.getAPStream(APStream, variant) : null

              cleanResolve(imageHandle)
              imageHandle && this.cacheAPStream(APStream, annotation)
            }
          }
        } catch (e) {
          reject(e)
        }
      }),
      cancel: cancelPromise,
    }
  }

  // Stores the provided imageHandle for caching under the pageIndex, annotation.id key
  cacheAPStream(APStream: APStream, annotation: AnnotationsUnion) {
    let cachedPageAPStreams = this.cachedAPStreams.get(annotation.pageIndex)

    if (!cachedPageAPStreams) {
      this.cachedAPStreams = this.cachedAPStreams.set(annotation.pageIndex, Map())
      cachedPageAPStreams = this.cachedAPStreams.get(annotation.pageIndex)
    }

    this.cachedAPStreams = this.cachedAPStreams.setIn(
      [annotation.pageIndex, annotation.id],
      APStream,
    )
  }

  // Releases and removes all AP streams cached for a given page.
  // Called when AnnotationLayerComponent unmounts.
  clearAllPageAPStreams(pageIndex: number) {
    const cachedPageAPStreams = this.cachedAPStreams.get(pageIndex)

    if (cachedPageAPStreams) {
      cachedPageAPStreams.forEach(APStream => {
        this.releaseAPStream(APStream)
      })
      this.cachedAPStreams = this.cachedAPStreams.delete(pageIndex)
    }

    this.pageAPStreamsPromises = this.pageAPStreamsPromises.delete(pageIndex)
  }

  // Releases and removes the specified AP streams cached for a given page.
  // Called when an annotation's AP stream is invalidated.
  clearPageAPStreams(pageIndex: number, annotationIds: Set<ID>) {
    const cachedPageAPStreams = this.cachedAPStreams.get(pageIndex)

    if (cachedPageAPStreams) {
      cachedPageAPStreams
        .filter((_APStream, annotationId) => annotationIds.has(annotationId))
        .forEach(APStream => {
          this.releaseAPStream(APStream)
        })
      this.cachedAPStreams = this.cachedAPStreams.updateIn([pageIndex], cachedPageAPStreams =>
        cachedPageAPStreams.filter((_APStream, annotationId) => !annotationIds.has(annotationId)),
      )
    }
  }

  getAPStream(
    APStream: AnnotationImageHandle | AnnotationVariantsImageHandles,
    variant?: IAnnotationVariant,
  ): AnnotationImageHandle | null {
    if (APStream instanceof ImageHandle) {
      return APStream
    }

    return APStream?.[variant || 'normal'] || null
  }

  renderAPStream(
    annotation: AnnotationsUnion,
    formFieldValue: FormFieldValue | null | undefined,
    blob: Blob | null | undefined,
    width: number,
    height: number,
    availableVariants: CoreAnnotationVariant[],
    variant?: IAnnotationVariant,
  ) {
    // When an annotation has other variants than `normal`, we render all of them at the same time
    // to prevent race conditions when some form fields change value at the same time that the
    // corrsponding variant actions are executed, like "down" for radio buttons and checkboxes, which
    // can result in the wrong AP stream being rendered. This improves perceived performance as well.
    if (availableVariants.length > 1) {
      const promises = availableVariants.map(availableVariant => {
        return (this as unknown as Backend).renderAnnotation(
          annotation,
          formFieldValue,
          blob,
          width,
          height,
          availableVariant !== 'normal' ? availableVariant : undefined,
        )
      })

      return {
        promise: promises,
        cancel: () => {
          promises.forEach(promise => {
            promise.cancel()
          })
        },
      }
    }

    return (this as unknown as Backend).renderAnnotation(
      annotation,
      formFieldValue,
      blob,
      width,
      height,
      variant,
    )
  }

  releaseAPStream(APStream: AnnotationImageHandle | AnnotationVariantsImageHandles) {
    if (APStream instanceof ImageHandle) {
      APStream.release()
    } else {
      Object.values(APStream).forEach(imageHandle => {
        imageHandle.release()
      })
    }
  }

  isVisuallyIdenticalStampAnnotationCached({
    annotation,
    width,
    height,
  }: {
    annotation: StampAnnotation
    width: number
    height: number
  }) {
    const visualAnnotationIndex = stringifyAnnotationVisualProperties(annotation)

    // Verify that the cached annotation is identical to the one we want to render.
    return (
      !!this._cachedRenderedAnnotation &&
      areStampAPStreamsIdentical({
        annotation,
        annotationVisualPropertiesString: visualAnnotationIndex,
        width,
        height,
        secondAnnotationVisualPropertiesString: this._cachedRenderedAnnotation.index,
        secondAnnotationWidth: this._cachedRenderedAnnotation.width,
        secondAnnotationHeight: this._cachedRenderedAnnotation.height,
      })
    )
  }

  cachedStampAnnotationDiscardablePromise({
    promise,
    resolve,
    reject,
  }: {
    promise: Promise<ImageHandle<HTMLImageElement> | undefined>
    resolve: (element: ImageHandle<HTMLImageElement> | undefined) => void
    reject: (error: Error) => void
  }) {
    invariant(this._cachedRenderedAnnotation)

    const annotationIndex = this._cachedRenderedAnnotation.index

    this._cachedRenderedAnnotation.APStreamPromise.then(result => {
      let imageHandle

      if (result) {
        imageHandle = new ImageHandle(
          result.element.cloneNode(true) as HTMLImageElement,
          result.release,
        )

        this._makeEnqueuedRelease(imageHandle, annotationIndex)
      }

      resolve(imageHandle)
    }).catch(reject)

    return {
      promise,
      cancel: () => {},
    }
  }
}
